#include <stdio.h>
int main() {
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &N);
        int bags = (N + 9) / 10;
        printf("%d\n", bags);
    }
    return 0;
}

